src/mapek/monitor.py:

```python
class Monitor:
    """MAPE-K 感知层：信号收集 + 缓冲 + 去重 + 格式化。

    ingest(signal) → 缓冲
    snapshot() → 返回当前窗口的 monitor_snapshot
    flush() → 清空缓冲区
    """

    def __init__(self, buffer_size: int = 100, dedup_window_s: int = 5):
        self._buffer: list[dict] = []
        self._buffer_size = buffer_size
        self._dedup_win = dedup_window_s

    def ingest(self, signal: dict) -> None:
        """收集一个信号，自动去重和缓冲管理。"""
        if self._is_duplicate(signal):
            return
        if len(self._buffer) >= self._buffer_size:
            self._buffer.pop(0)  # 丢弃最旧
        self._buffer.append(signal)

    def snapshot(self) -> dict:
        """返回当前缓冲区的快照。"""
        return {
            "signals": list(self._buffer),
            "count": len(self._buffer),
            "earliest": self._buffer[0].get("timestamp") if self._buffer else None,
            "latest": self._buffer[-1].get("timestamp") if self._buffer else None,
        }

    def flush(self) -> list[dict]:
        """清空缓冲区并返回历史信号。"""
        data = list(self._buffer)
        self._buffer.clear()
        return data

    def _is_duplicate(self, signal: dict) -> bool:
        """检查是否与最近信号重复（基于 content + timestamp 窗口）。"""
        if not self._buffer:
            return False
        last = self._buffer[-1]
        # 相同内容 + 时间窗口内 → 去重
        if signal.get("content") == last.get("content"):
            from datetime import datetime, timezone
            now = datetime.now(timezone.utc).timestamp()
            last_ts = self._parse_ts(last.get("timestamp"))
            if last_ts and (now - last_ts) < self._dedup_win:
                return True
        return False

    def _parse_ts(self, ts_str: str | None) -> float | None:
        if not ts_str:
            return None
        try:
            from datetime import datetime
            return datetime.fromisoformat(ts_str.replace("Z", "+00:00")).timestamp()
        except Exception:
            return None
```

src/mapek/analyze.py:

```python
class Analyze:
    """MAPE-K 分析层：状态深层诊断 + 趋势检测 + 异常识别。

    diagnose(monitor_snapshot) → analysis_report
    """

    def __init__(self, min_confidence: float = 0.3):
        self._min_conf = min_confidence

    def diagnose(self, snapshot: dict) -> dict:
        """对 Monitor snapshot 做分析诊断。"""
        signals = snapshot.get("signals", [])
        return {
            "trends": self._detect_trends(signals),
            "anomalies": self._detect_anomalies(signals),
            "causal_signals": self._extract_causal_signals(signals),
            "confidence": self._compute_confidence(signals),
            "summary": self._summarize(signals),
        }

    def _detect_trends(self, signals: list[dict]) -> list[dict]:
        """简单趋势检测：计算最近窗口均值变化方向。"""
        if len(signals) < 4:
            return [{"metric": "insufficient_data", "direction": "unknown"}]

        half = len(signals) // 2
        recent = signals[half:]
        older = signals[:half]

        trends = []
        for metric in self._detectable_metrics(signals):
            older_avg = self._avg_metric(older, metric)
            recent_avg = self._avg_metric(recent, metric)
            if recent_avg > older_avg * 1.1:
                direction = "rising"
            elif recent_avg < older_avg * 0.9:
                direction = "falling"
            else:
                direction = "stable"
            trends.append({"metric": metric, "direction": direction,
                           "older_avg": older_avg, "recent_avg": recent_avg})
        return trends

    def _detect_anomalies(self, signals: list[dict]) -> list[dict]:
        """简单异常检测：偏离均值超过 2 倍标准差。"""
        if len(signals) < 3:
            return []
        anomalies = []
        for metric in self._detectable_metrics(signals):
            values = [s.get(metric, 0) for s in signals if metric in s]
            if not values:
                continue
            avg = sum(values) / len(values)
            var = sum((v - avg) ** 2 for v in values) / len(values)
            std = var ** 0.5 if var > 0 else 0.1
            for i, s in enumerate(signals):
                val = s.get(metric, 0)
                if abs(val - avg) > 2 * std:
                    anomalies.append({"index": i, "metric": metric,
                                      "value": val, "expected": avg,
                                      "deviation_std": round(abs(val - avg) / std, 2)})
        return anomalies

    def _extract_causal_signals(self, signals: list[dict]) -> list[dict]:
        """提取可能的因果信号（相关性不等于因果，仅做方向排序）。"""
        return [{"note": "Lightweight correlation analysis — requires MRT for causal claims"}]

    def _compute_confidence(self, signals: list[dict]) -> float:
        """基于信号量计算分析置信度。"""
        if len(signals) < 2:
            return 0.0
        return round(min(1.0, len(signals) / 20.0 * 0.5 + 0.3), 4)

    def _summarize(self, signals: list[dict]) -> str:
        count = len(signals)
        anomaly_count = len(self._detect_anomalies(signals))
        if anomaly_count > count * 0.3:
            return f"High anomaly ratio ({anomaly_count}/{count}) — recommend intervention"
        elif anomaly_count > 0:
            return f"Acceptable state with {anomaly_count} minor anomalies"
        return "Normal operation — no anomalies detected"

    def _detectable_metrics(self, signals: list[dict]) -> list[str]:
        """提取所有信号中共有的数值型指标。"""
        if not signals:
            return []
        # 取第一个信号的数值键作为可检测指标
        numeric_keys = []
        for k, v in signals[0].items():
            if isinstance(v, (int, float)):
                numeric_keys.append(k)
        return numeric_keys

    def _avg_metric(self, signals: list[dict], metric: str) -> float:
        vals = [s.get(metric, 0) for s in signals if metric in s]
        return sum(vals) / len(vals) if vals else 0.0
```

设计说明：
- Analyze 使用简单统计方法（均值/标准差），不做复杂 ML
- 因果信号提取是占位（return placeholder），真实因果推断在 Phase 7 的 MRT 中实现
- min_confidence 决定分析结果是否值得送给 Plan 组件
